// 在消息处理函数中添加所有事件类型
function handleMessage(event: MessageEvent) {
  try {
    const message = JSON.parse(event.data);

    switch (message.event) {
      case 'iteration.status_changed':
        // 更新迭代状态
        emit('iteration:status', message.data);
        break;

      case 'iteration.progress':
        // 更新迭代进度
        emit('iteration:progress', message.data);
        break;

      case 'iteration.completed':
        // 迭代完成
        emit('iteration:completed', message.data);
        showNotification(`迭代 #${message.data.iteration} 完成`, 'success');
        break;

      case 'agent.status_changed':
        // Agent 状态变化
        emit('agent:status', message.data);
        break;

      case 'agent.progress':
        // Agent 进度更新
        emit('agent:progress', message.data);
        break;

      case 'system.metrics':
        // 系统指标
        emit('system:metrics', message.data);
        break;

      case 'log.entry':
        // 日志条目
        emit('log:entry', message.data);
        break;

      case 'ping':
        // 心跳响应
        send({ event: 'pong' });
        break;

      default:
        console.log('未知 WebSocket 事件:', message);
    }
  } catch (error) {
    console.error('WebSocket 消息处理错误:', error);
  }
}
