1. **后端实时服务完善**
```typescript
// src/dashboard/services/realtime.service.ts
export class RealtimeService {
  private clients: Set<WebSocket> = new Set()
  private subscriptions: Map<string, Set<WebSocket>> = new Map()

  // 广播迭代状态变化
  broadcastIterationStatus(iteration: Iteration) {
    this.publish('iterations', {
      type: 'iteration.status_changed',
      data: iteration
    })
  }

  // 广播迭代进度
  broadcastIterationProgress(iterationId: string, progress: number) {
    this.publish('iterations', {
      type: 'iteration.progress',
      data: { id: iterationId, progress }
    })
  }

  // 广播Agent状态
  broadcastAgentStatus(agent: AgentState) {
    this.publish('agents', {
      type: 'agent.status_changed',
      data: agent
    })
  }

  // 订阅频道
  subscribe(client: WebSocket, channel: string) {
    if (!this.subscriptions.has(channel)) {
      this.subscriptions.set(channel, new Set())
    }
    this.subscriptions.get(channel)!.add(client)
  }

  // 发布消息
  private publish(channel: string, message: ServerEvent) {
    const subscribers = this.subscriptions.get(channel)
    if (subscribers) {
      const data = JSON.stringify(message)
      subscribers.forEach(client => {
        if (client.readyState === WebSocket.OPEN) {
          client.send(data)
        }
      })
    }
  }
}
```

2. **前端WebSocket管理**
```typescript
// dashboard/src/stores/websocket.ts
export const useWebSocketStore = defineStore('websocket', () => {
  const isConnected = ref(false)
  const socket = ref<WebSocket | null>(null)
  const reconnectAttempts = ref(0)
  const maxReconnectAttempts = 5

  function connect() {
    const wsUrl = import.meta.env.VITE_WS_URL || 'ws://localhost:3000/ws'
    socket.value = new WebSocket(wsUrl)

    socket.value.onopen = () => {
      isConnected.value = true
      reconnectAttempts.value = 0

      // 订阅所有频道
      send({
        type: 'subscribe',
        channels: ['iterations', 'agents', 'logs', 'metrics']
      })
    }

    socket.value.onmessage = (event) => {
      try {
        const message = JSON.parse(event.data) as ServerEvent
        handleMessage(message)
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error)
      }
    }

    socket.value.onclose = () => {
      isConnected.value = false

      // 自动重连
      if (reconnectAttempts.value < maxReconnectAttempts) {
        setTimeout(() => {
          reconnectAttempts.value++
          connect()
        }, 1000 * reconnectAttempts.value)
      }
    }
  }

  function handleMessage(message: ServerEvent) {
    switch (message.type) {
      case 'iteration.status_changed':
        useIterationStore().updateIteration(message.data)
        break
      case 'iteration.progress':
        useIterationStore().updateProgress(message.data.id, message.data.progress)
        break
      case 'agent.status_changed':
        useAgentStore().updateAgent(message.data)
        break
      case 'system.metrics':
        useOverviewStore().updateMetrics(message.data)
        break
    }
  }

  return { isConnected, connect }
})
```

