```typescript
// src/auto-iteration.ts
export class AutoIterationEngine {
  private realtimeService: RealtimeService
  private iterationService: IterationService

  constructor() {
    const services = getDashboardServices()
    this.realtimeService = services.realtimeService
    this.iterationService = services.iterationService
  }

  async start() {
    // 创建迭代记录
    const iteration = await this.iterationService.create({
      iterationNumber: this.count,
      status: 'running',
      requirement: this.requirement
    })

    // 推送状态变化
    this.realtimeService.broadcastIterationStatus(iteration)

    // 执行产品经理分析
    await this.runProductManager()

    // 执行架构师设计
    await this.runArchitect()

    // 执行开发阶段
    await this.runDevelopment()

    // 完成迭代
    await this.complete(iteration)
  }

  private async runProductManager() {
    // 推送Agent状态
    this.realtimeService.broadcastAgentStatus({
      name: 'product-manager',
      status: 'running',
      currentTask: '分析需求中...'
    })

    const result = await this.productManager.execute(this.requirement)

    // 推送完成状态
    this.realtimeService.broadcastAgentStatus({
      name: 'product-manager',
      status: 'success',
      currentTask: '需求分析完成'
    })

    return result
  }

  private async complete(iteration: Iteration) {
    // Git提交
    const commit = await this.gitCommit()

    // 保存提交记录
    await this.iterationService.addCommit(iteration.id, commit)

    // 更新迭代状态
    await this.iterationService.update(iteration.id, {
      status: 'success',
      progress: 100,
      completedAt: new Date()
    })

    // 推送完成事件
    this.realtimeService.broadcastIterationCompleted({
      iteration,
      commitHash: commit.hash,
      filesChanged: commit.filesChanged
    })
  }
}
```

