import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private iterationService: IterationService
  private realtimeService: RealtimeService

  async start() {
    const services = getServices()
    this.iterationService = services.iterationService
    this.realtimeService = services.realtimeService

    // 创建迭代记录
    const iteration = await this.iterationService.create({
      iterationNumber: this.count,
      status: 'running',
      requirement: this.requirement
    })

    // 推送状态
    this.realtimeService.broadcastIterationStatus(iteration)
  }

  async runPhase(phase: string, agent: BaseAgent) {
    // 推送 Agent 状态
    this.realtimeService.broadcastAgentStatus({
      name: agent.name,
      status: 'running',
      currentTask: `${phase} 进行中...`
    })

    // 执行 Agent
    const result = await agent.execute(this.requirement)

    // 推送完成状态
    this.realtimeService.broadcastAgentStatus({
      name: agent.name,
      status: 'success',
      currentTask: `${phase} 已完成`
    })

    // 更新进度
    const progress = this.calculateProgress()
    this.realtimeService.broadcastIterationProgress(iteration.id, progress)
  }

  async complete() {
    // Git 提交
    const commitResult = await this.gitCommit()

    // 保存提交记录
    await this.iterationService.addCommit(iteration.id, commitResult)

    // 更新迭代状态
    await this.iterationService.update(iteration.id, {
      status: 'success',
      progress: 100,
      completedAt: new Date()
    })

    // 推送完成事件
    this.realtimeService.broadcastIterationCompleted({
      iteration: iteration,
      commitHash: commitResult.hash,
      filesChanged: commitResult.filesChanged
    })
  }
}
