      const { getServices } = require('./dashboard/server');
      const services = getServices();
      this.iterationService = services.iterationService;
      this.realtimeService = services.realtimeService;
      console.log('✅ Dashboard 服务已连接');
    } catch (error) {
      console.log('ℹ️ Dashboard 服务未启动，将在需要时启动');
    }
  }
}

// 2. 在 runIteration() 开始时推送状态
async runIteration(): Promise<void> {
  console.log(`\n🔄 迭代 #${this.iterationCount}`);

  let iterationId: string | undefined;

  try {
    // 产品经理发现需求
    const task = await this.productManager.discoverTask(this.config.projectPath);
    console.log(`📋 任务: ${task.description}`);

    // 如果有 Dashboard 服务，创建迭代记录
    if (this.iterationService) {
      const iteration = await this.iterationService.create({
        iterationNumber: this.iterationCount,
        status: 'running',
        requirement: task.description,
        pmAnalysis: task.analysis
      });
      iterationId = iteration.id;

      // 推送状态到 Dashboard
      this.realtimeService?.broadcastIterationStatusChange({
        iterationId: iteration.id,
        iterationNumber: this.iterationCount,
        status: 'running',
        requirement: task.description,
        progress: 0
      });
    }

    // ... 执行各个 Agent

    // 3. 在每个 Agent 执行时推送进度
    const totalAgents = Object.keys(this.agents).length;
    let completedAgents = 0;

    for (const [name, agent] of Object.entries(this.agents)) {
      const progress = Math.round((completedAgents / totalAgents) * 100);

      this.realtimeService?.broadcastAgentStatusChange({
        agentName: name,
        status: 'running',
        currentTask: `${name} 进行中...`,
        progress: 0
      });

      await agent.execute(task.description);

      completedAgents++;
      const newProgress = Math.round((completedAgents / totalAgents) * 100);

      this.realtimeService?.broadcastAgentStatusChange({
        agentName: name,
        status: 'success',
        currentTask: `${name} 已完成`,
        progress: 100
      });

      this.realtimeService?.broadcastIterationProgress({
        iterationId: iterationId!,
        progress: newProgress
      });
    }

    // 4. 迭代完成时推送
    if (this.iterationService && iterationId) {
      await this.iterationService.update(iterationId, {
        status: 'success',
        progress: 100,
        completedAt: new Date()
      });

      this.realtimeService?.broadcastIterationStatusChange({
        iterationId,
        iterationNumber: this.iterationCount,
        status: 'success',
        requirement: task.description,
        progress: 100
      });
    }

  } catch (error) {
    // 错误处理
    if (this.iterationService && iterationId) {
      await this.iterationService.update(iterationId, {
        status: 'failed',
        error_message: String(error)
      });
    }
  }
}
