**具体实现**:

```typescript
// dashboard/src/utils/websocket-manager.ts (如果不存在则创建)

import { ref, reactive } from 'vue'

export enum ConnectionState {
  DISCONNECTED = 'disconnected',
  CONNECTING = 'connecting',
  CONNECTED = 'connected',
  RECONNECTING = 'reconnecting',
  ERROR = 'error'
}

export function useWebSocket() {
  const state = reactive({
    connectionState: ConnectionState.DISCONNECTED,
    connected: false,
    reconnectAttempts: 0,
    lastError: null as Error | null,
    url: ''
  })

  const eventHandlers = new Map<string, Set<Function>>()
  let socket: WebSocket | null = null
  let reconnectTimer: ReturnType<typeof setTimeout> | null = null
  const maxReconnectAttempts = 5

  function connect(url?: string) {
    if (socket?.readyState === WebSocket.OPEN) {
      console.log('WebSocket 已连接')
      return
    }

    state.url = url || import.meta.env.VITE_WS_URL || 'ws://localhost:3000/ws'
    state.connectionState = ConnectionState.CONNECTING

    socket = new WebSocket(state.url)

    socket.onopen = () => {
      state.connectionState = ConnectionState.CONNECTED
      state.connected = true
      state.reconnectAttempts = 0
      state.lastError = null
      console.log('✅ WebSocket 已连接')

      // 订阅频道
      send('subscribe', { channel: 'all' })
    }

    socket.onmessage = (event) => {
      try {
        const message = JSON.parse(event.data)

        // 处理 ping/pong
        if (message.event === 'ping') {
          send('pong')
          return
        }

        // 分发事件
        const handlers = eventHandlers.get(message.event)
        if (handlers) {
          handlers.forEach(handler => handler(message.data))
        }

        // 通用事件监听器
        const allHandlers = eventHandlers.get('*')
        if (allHandlers) {
          allHandlers.forEach(handler => handler(message))
        }
      } catch (error) {
        console.error('WebSocket 消息解析错误:', error)
      }
    }

    socket.onclose = () => {
      state.connectionState = ConnectionState.DISCONNECTED
      state.connected = false

      // 自动重连
      if (state.reconnectAttempts < maxReconnectAttempts) {
        state.connectionState = ConnectionState.RECONNECTING
        state.reconnectAttempts++

        const delay = Math.min(1000 * Math.pow(2, state.reconnectAttempts), 10000)
        reconnectTimer = setTimeout(() => {
          console.log(`🔄 WebSocket 重连中 (${state.reconnectAttempts}/${maxReconnectAttempts})...`)
          connect()
        }, delay)
      }
    }

    socket.onerror = (error) => {
      state.connectionState = ConnectionState.ERROR
      state.lastError = error as Error
      console.error('WebSocket 错误:', error)
    }
  }

  function disconnect() {
    if (reconnectTimer) {
      clearTimeout(reconnectTimer)
      reconnectTimer = null
    }

    if (socket) {
      socket.close()
      socket = null
    }

    state.connectionState = ConnectionState.DISCONNECTED
    state.connected = false
  }

  function send(event: string, data?: any) {
    if (socket?.readyState === WebSocket.OPEN) {
      socket.send(JSON.stringify({ event, data }))
    }
  }

  function on(event: string, callback: Function) {
    if (!eventHandlers.has(event)) {
      eventHandlers.set(event, new Set())
    }
    eventHandlers.get(event)!.add(callback)

    // 返回取消订阅函数
    return () => off(event, callback)
  }

  function off(event: string, callback: Function) {
    const handlers = eventHandlers.get(event)
    if (handlers) {
      handlers.delete(callback)
    }
  }

  return {
    state,
    connect,
    disconnect,
    send,
    on,
    off
  }
}
