// dashboard/src/stores/iteration.ts

import { defineStore } from 'pinia'
import { ref, computed } from 'vue'
import { useWebSocketStore } from './websocket'

export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<Iteration[]>([])
  const currentIteration = ref<Iteration | null>(null)
  const loading = ref(false)
  const total = ref(0)

  // 从 WebSocket 更新迭代状态
  function updateIterationStatus(data: IterationStatusChange) {
    const iteration = {
      id: data.iterationId,
      iterationNumber: data.iterationNumber,
      status: data.status,
      requirement: data.requirement,
      progress: data.progress,
      createdAt: new Date(),
      updatedAt: new Date()
    }

    // 更新列表
    const index = iterations.value.findIndex(i => i.id === data.iterationId)
    if (index !== -1) {
      iterations.value[index] = iteration
    } else {
      iterations.value.unshift(iteration)
    }

    // 更新当前迭代
    if (data.status === 'running') {
      currentIteration.value = iteration
    } else if (currentIteration.value?.id === data.iterationId && data.status === 'success') {
      currentIteration.value = null
    }
  }

  // 更新进度
  function updateProgress(data: IterationProgress) {
    const iteration = iterations.value.find(i => i.id === data.iterationId)
    if (iteration) {
      iteration.progress = data.progress
    }
    if (currentIteration.value?.id === data.iterationId) {
      currentIteration.value.progress = data.progress
    }
  }

  // 标记完成
  function markIterationCompleted(data: any) {
    if (currentIteration.value?.id === data.iteration.id) {
      currentIteration.value = null
    }

    const iteration = iterations.value.find(i => i.id === data.iteration.id)
    if (iteration) {
      iteration.status = 'success'
      iteration.progress = 100
      iteration.completedAt = new Date()
    }
  }

  // 监听 WebSocket 事件
  function setupWebSocketListeners() {
    const wsStore = useWebSocketStore()

    wsStore.on('iteration.status_changed', updateIterationStatus)
    wsStore.on('iteration.progress', updateProgress)
    wsStore.on('iteration.completed', markIterationCompleted)
  }

  return {
    iterations,
    currentIteration,
    loading,
    total,
    updateIterationStatus,
    updateProgress,
    markIterationCompleted,
    setupWebSocketListeners
  }
})
