```typescript
// src/dashboard/routes/iterations.ts

import { FastifyInstance } from 'fastify';

export async function iterationRoutes(fastify: FastifyInstance, services: any) {
  const { iterationService } = services;

  // GET /iterations - 获取迭代列表
  fastify.get('/iterations', async (request, reply) => {
    const { page = 1, pageSize = 20, status, keyword } = request.query as any;

    const result = await iterationService.list({
      page: Number(page),
      pageSize: Number(pageSize),
      status,
      keyword
    });

    return reply.send({
      success: true,
      data: result
    });
  });

  // GET /iterations/:id - 获取迭代详情
  fastify.get('/iterations/:id', async (request, reply) => {
    const { id } = request.params as { id: string };

    const iteration = await iterationService.getById(id);

    if (!iteration) {
      return reply.code(404).send({
        success: false,
        error: {
          code: 'ITERATION_NOT_FOUND',
          message: '迭代不存在'
        }
      });
    }

    return reply.send({
      success: true,
      data: iteration
    });
  });

  // GET /iterations/current - 获取当前运行迭代
  fastify.get('/iterations/current', async (request, reply) => {
    const iteration = await iterationService.getCurrent();

    return reply.send({
      success: true,
      data: iteration
    });
  });

  // POST /iterations/:id/rollback - 回滚到指定迭代
  fastify.post('/iterations/:id/rollback', async (request, reply) => {
    const { id } = request.params as { id: string };
    const { createBackup = true } = request.body as any;

    try {
      const result = await iterationService.rollback(id, createBackup);

      return reply.send({
        success: true,
        data: result
      });
    } catch (error) {
      return reply.code(500).send({
        success: false,
        error: {
          code: 'ROLLBACK_FAILED',
          message: error.message
        }
      });
    }
  });
}
