```typescript
// dashboard/src/stores/websocket.ts
import { useIterationStore } from './iteration'
import { useAgentStore } from './agent'
import { useOverviewStore } from './overview'
import { useLogStore } from './log'
import { ElMessage } from 'element-plus'

export const useWebSocketStore = defineStore('websocket', () => {
  const wsManager = useWebSocket()

  // 处理 WebSocket 消息
  function handleMessage(event: WSEvent) {
    const { type, data } = event

    switch (type) {
      case 'iteration.status_changed':
        useIterationStore().updateIteration(data)
        break

      case 'iteration.progress':
        useIterationStore().updateProgress(data.id, data.progress)
        break

      case 'agent.status_changed':
        useAgentStore().updateAgent(data)
        break

      case 'agent.progress':
        useAgentStore().updateProgress(data.name, data.progress)
        break

      case 'system.metrics':
        useOverviewStore().updateMetrics(data)
        break

      case 'log.entry':
        useLogStore().addLog(data)
        break

      case 'iteration.completed':
        useIterationStore().markCompleted(data)
        ElMessage.success(`迭代 #${data.iterationNumber} 已完成`)
        break

      case 'error':
        ElMessage.error(data.message)
        break

      default:
        console.warn('Unknown WebSocket event type:', type)
    }
  }

  // 连接时注册消息处理
  wsManager.on('message', handleMessage)

  return {
    connected: computed(() => wsManager.state.connected),
    connect: () => wsManager.connect(),
    disconnect: () => wsManager.disconnect()
  }
})
```

