```typescript
// src/auto-iteration.ts
import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private realtimeService?: RealtimeService

  async start() {
    // 获取 Dashboard 服务（如果已启动）
    try {
      const services = getServices()
      this.realtimeService = services.realtimeService
    } catch {
      // Dashboard 未启动，忽略
    }

    // 开始迭代...
    await this.runIteration()
  }

  async runIteration() {
    // 创建迭代
    const iteration = await this.createIteration()

    // 推送状态
    this.pushState('iteration.status_changed', iteration)

    // 执行产品经理
    await this.runAgent('product-manager', '分析需求')

    // 执行架构师
    await this.runAgent('architect', '设计架构')

    // ... 其他 agents

    // 完成迭代
    await this.completeIteration()
  }

  async runAgent(agentName: string, task: string) {
    // 推送 Agent 状态
    this.pushState('agent.status_changed', {
      name: agentName,
      status: 'running',
      currentTask: task
    })

    // 执行 Agent...
    const result = await agent.execute()

    // 推送完成状态
    this.pushState('agent.status_changed', {
      name: agentName,
      status: 'success',
      currentTask: `${task} 已完成`
    })
  }

  pushState(event: string, data: any) {
    if (this.realtimeService) {
      switch(event) {
        case 'iteration.status_changed':
          this.realtimeService.broadcastIterationStatusChange(data)
          break
        case 'agent.status_changed':
          this.realtimeService.broadcastAgentStatusChange(data)
          break
        case 'iteration.progress':
          this.realtimeService.broadcastIterationProgress(data)
          break
      }
    }
  }
}
